WebLink.url:
{!REQUIRESCRIPT("/support/console/33.0/integration.js")}
{!REQUIRESCRIPT("/soap/ajax/22.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/22.0/apex.js" )} 
if (typeof(srcUp) == 'function') { 
console.log("sforce: %o", sforce); 
sforce.console.getEnclosingPrimaryTabId(function(response) {
var primaryTabId = response.id; 
console.log("primaryTabId: %o", primaryTabId); 

var connection = sforce.connection; 
sforce.connection.sessionId = '{!$Api.Session_ID}'; 
var caseid = "{!Case.Id}"; 
var leadid= sforce.apex.execute("CreateCase","createleadrecord",{Caseid:"{!Case.Id}"}); 

var url = "{!URLFOR($Action.Lead.View,'00Q000000000000000')}";
url = url.replace("00Q000000000000000", leadid);
var isActive = true;
var tabLabel = null;
var subtabId = null;

sforce.console.openSubtab(
    primaryTabId, url, isActive, tabLabel, subtabId);
});
}
else{ 
var connection = sforce.connection; 
sforce.connection.sessionId = '{!$Api.Session_ID}'; 
var caseid = "{!Case.Id}"; 
var leadid= sforce.apex.execute("CreateCase","createleadrecord",{Caseid:"{!Case.Id}"}); 
window.open('/'+leadid);
}
